去反射把所有的 c# 类的public成员变量、成员函数，都导出到一个相对应的Wrap类中，而这些成员函数通过特殊的标记，映射到 lua 的虚拟机中，当在 lua 中调用相对应的函数时候，直接调用映射进去的wrap函数，然后再调用到实际的 c# 类，完成调用过程
Wrap在 tolua 生成的 Wrap 文件中，经常遇见如此写法
// XXXWrap.csL.BeginStaticLibs(&quot;XXX&quot;);L.RegFunction(&quot;Log&quot;, Log);L.EndStaticLibs();

BeginStaticLibs首先BeginStaticLibs最终会走到这条语句上来：LuaDLL.tolua_beginstaticclass(L, name);这语句会执行 tolua.dll 的 C 语言对应方法，tolua_beginstaticclass，该方法最终会在lua_State栈顶生成一个名为 name 的table
/* tolua.c */LUALIB_API void tolua_beginstaticclass(lua_State *L, const char *name)&#123;        lua_pushstring(L, name);  /* 将 name 压入栈中，即 XXX */    lua_newtable(L);/* 创建一个 table 压入栈中*/    _addtoloaded(L);    lua_pushvalue(L, -1);      /* 这里将栈顶表复制了一份压入栈中 即 top [XXX(table),XXX(emptytable)] bottom    */    /* 以上操作相当于生成了名为 name 的 table :XXX = &#123;&#125;  */       /* 以下操作抽象理解 */    /* XXX[&quot;userdata&quot;] = &amp;tag  */    lua_pushlightuserdata(L, &amp;tag);    lua_pushnumber(L, 1);    lua_rawset(L, -3);    /* XXX[&quot;.name&quot;] = XXX  */    lua_pushstring(L, &quot;.name&quot;);    _pushfullname(L, -4);    lua_rawset(L, -3);       /* XXX[&quot;__index&quot;] = static_index_event  */    lua_pushstring(L, &quot;__index&quot;);    lua_pushcfunction(L, static_index_event);    lua_rawset(L, -3);    /* XXX[&quot;__newindex&quot;] = static_newindex_event  */    lua_pushstring(L, &quot;__newindex&quot;);    lua_pushcfunction(L, static_newindex_event);    lua_rawset(L, -3);      &#125;



    最终会在 lua_State 栈顶会被压入一个名为 XXX 的 Table


EndStaticLibs接着先把尾给收掉，EndStaticLibs最后会来到tolua.c这边的tolua_endstaticclass方法，该方法最终会将栈顶元素弹出并将其设置为 - 2 位置的元表
/* tolua.c */LUALIB_API void tolua_endstaticclass(lua_State *L)&#123;    lua_setmetatable(L, -2);    lua_rawset(L, -3);    &#125;



    弹出栈顶元素，将其设置为 XXX(Empty Table) 的元表


RegFunctionRegFunction先是将要注册的方法转换成了供平台使用的指针，传递到 C 中生成可以供 lua 使用的LuaCSFunction函数
// LuaState.cspublic void RegFunction(string name, LuaCSFunction func)&#123;    IntPtr fn = Marshal.GetFunctionPointerForDelegate(func);    LuaDLL.tolua_function(L, name, fn);            &#125;

tolua.c 文件中tolua_function对传入进的函数进行了绑定
/* tolua.c */LUALIB_API void tolua_function(lua_State *L, const char *name, lua_CFunction fn)&#123;    lua_pushstring(L, name);    tolua_pushcfunction(L, fn);    lua_rawset(L, -3); // 赋值操作：将栈顶作为 v:CClosure，倒数第二位作为 k:name，-3 位置作为 table 进行赋值 ，即 XXX[name] = CClosure&#125;LUA_API int tolua_pushcfunction(lua_State *L, lua_CFunction fn)&#123;            lua_pushboolean(L, 0); // 压入布尔值 false top [0(false),name,XXX(table)] bottom    lua_pushcfunction(L, fn); // 压入函数，这里会以 CClosure 结构体的形式被压入栈    lua_pushcclosure(L, tolua_closure, 2); // 这里会创建一个新的 CClosure 结构，并将栈顶 2 个元素（一个布尔值与一个存放了 fn 的 Closure) 弹出并压入 CClosure 结构体中，最终将新的 CClosure 压入栈中    return 0;&#125;


lua_rawset(L, -3); 
 赋值操作：将栈顶作为值——CClosure，倒数第二位作为键——name，-3 位置作为 table 进行赋值 ，即XXX[name] = CClosure





实际上一个 C#方法的指针其实被封装了两层：

lua_pushcfunction(L, fn)时 将fn封装进了CClosure中
lua_pushcclosure(L, tolua_closure, 2)时将封装了fn的CClosure再一次封装进了新的CClosure中

当在 lua 中调用注册的方法时，实际上是在调用最外层的CClosure结构体，它其中的方法是tolua_closure，而 C#方法指针fn作为该结构体栈中的值被存放着upvalue
static int tolua_closure(lua_State *L)&#123;    /*  获取到所注册的 C#方法指针 */    lua_CFunction fn = (lua_CFunction)lua_tocfunction(L, lua_upvalueindex(2));    /*  运行 ，因为 lua 跨语言的数据交互都借助栈来完成，所以运行结果都是通过获取栈中元素来获得 */    int r = fn(L);           if (lua_toboolean(L, lua_upvalueindex(1)))    &#123;        lua_pushboolean(L, 0);        lua_replace(L, lua_upvalueindex(1));        return lua_error(L);    &#125;       return r;&#125;


lua_pushfunction：实际上压入函数的过程就是形成闭包的过程，在 lua 中函数是以闭包的形式被保存的
/* lua.h */#define lua_pushcfunction(L,f)  lua_pushcclosure(L, (f), 0) /* 宏 压入闭包方法 n 为 0 */
lua_pushclosure：生成闭包，将函数存放在闭包结构体中，并将栈顶 n 个元素一同压入闭包内的栈
typedef struct CClosure &#123;  ClosureHeader;  lua_CFunction f;  TValue upvalue[1];  /* list of upvalues */&#125; CClosure;/* lua.h */LUA_API void  (lua_pushcclosure) (lua_State *L, lua_CFunction fn, int n);/* lapi.c */LUA_API void lua_pushcclosure (lua_State *L, lua_CFunction fn, int n) &#123;  lua_lock(L);  if (n == 0) &#123;    setfvalue(L-&gt;top, fn);    api_incr_top(L);  &#125;  else &#123;    CClosure *cl;      api_checknelems(L, n);    api_check(L, n &lt;= MAXUPVAL, &quot;upvalue index too large&quot;);  /* #define MAXUPVAL 255  */    cl = luaF_newCclosure(L, n);/* 创建了闭包结构体  */    cl-&gt;f = fn;    L-&gt;top -= n;  /* 将栈顶 n 个元素移除并压入闭包的栈中 upvalue */    while (n--) &#123;      setobj2n(L, &amp;cl-&gt;upvalue[n], L-&gt;top + n);      /* does not need barrier because closure is white */    &#125;    setclCvalue(L, L-&gt;top, cl);    api_incr_top(L);    luaC_checkGC(L);  &#125;  lua_unlock(L);&#125;





